import React from "react";
import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022-Present",
    icon: <FaBriefcase />,
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2024",
    icon: <FaUniversity />,
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022",
    icon: <FaUniversity />,
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021-2022",
    icon: <FaBriefcase />,
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014-2021",
    icon: <FaBriefcase />,
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013-2014",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008-2013",
    icon: <FaBriefcase />,
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001-2008",
    icon: <FaBriefcase />,
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001-2006",
    icon: <FaUniversity />,
  }
];

const ExperienceTimeline = () => {
  return (
    <div className="overflow-x-auto py-10">
      <div className="flex relative items-center justify-start min-w-[1500px]">
        {/* Línea horizontal */}
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-300 z-0" />

        {experienceData.map((item, index) => {
          const isTop = index % 2 === 0;

          return (
            <div key={index} className="relative flex flex-col items-center w-48 mx-4 z-10">
              {/* Contenedor superior o inferior según el índice */}
              <div className={`mb-2 ${isTop ? "order-1" : "order-3"} text-center`}>
                <div
                  className={`rounded-lg shadow-md px-3 py-2 text-sm ${
                    index % 2 === 0
                      ? "bg-gradient-to-r from-black via-gray-800 to-white text-white"
                      : "bg-gradient-to-r from-blue-600 via-blue-300 to-white text-black"
                  }`}
                >
                  <p className="text-xs italic text-gray-200">{item.date}</p>
                  <p className="font-semibold text-sm">{item.title}</p>
                  <p className="text-xs">{item.company}</p>
                </div>
              </div>

              {/* Icono central */}
              <div className="w-10 h-10 flex items-center justify-center bg-white rounded-full border-2 border-gray-400 z-10">
                {item.icon}
              </div>

              {/* Espaciador inferior o superior para mantener alineado */}
              <div className={`mt-2 ${isTop ? "order-3" : "order-1"}`} />
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default ExperienceTimeline;
